window.__QUIZ_DATA__=[{"id":"theory>Geography>2024 Paper 2>1>a","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Differentiate between primary and secondary industries","images":[],"marking_scheme":"(i) Primary industries involve the extraction and production of raw materials while Secondary industries, on the other hand, are involved in the processing of raw materials into finished products.  (ii) Examples of primary industries include agriculture, fishing, forestry, and mining while Examples of secondary industries include manufacturing, construction, and production of goods such as automobiles, textiles, and electronics.  (iii) Primary industries are usually located in rural areas and are often labor-intensive, relying on natural resources while secondary industries are typically located in urban areas and are more capital-intensive, relying on machinery and technology.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>1>b","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Outline four reasons for the predominance of light industries in developing countries","images":[],"marking_scheme":"(i) Lower Capital Requirement: Light industries often require less initial investment compared to heavy industries, making them more accessible for developing countries with limited financial resources.  (ii) Labor-Intensive Nature: Light industries are generally more labor-intensive, providing employment opportunities for a large workforce, which is often abundant in developing countries.  (iii) Raw Material Availability: Many developing countries have easy access to raw materials suitable for light industries, such as textiles, food processing, and handicrafts.  (iv) Market Demand: There is a high local and regional demand for the goods produced by light industries, such as clothing, food items, and household products.  (v) Small Scale Operations: Light industries can operate on a smaller scale, which is suitable for the economic structures of many developing countries where large-scale industrial operations may be impractical.  (vi) Government Support: Many developing countries provide incentives and support for light industries as a means to boost employment and stimulate economic growth.  (vii) Lower Environmental Impact: Light industries typically have a lower environmental impact compared to heavy industries, which is crucial for developing countries facing environmental challenges and limited regulatory frameworks.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>1>c","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Highlight four contributions of the industrial sector to the economic devclopment of developing countries.","images":[],"marking_scheme":"(i) Job Creation: The industrial sector generates a significant number of employment opportunities, reducing unemployment rates and improving the standard of living for many people.  (ii) Economic Diversification: Industrialization helps diversify the economy, reducing dependency on agriculture and raw materials, thereby stabilizing economic growth.  (iii) Increased GDP: Industrial activities contribute to a higher Gross Domestic Product (GDP) by producing goods and services, boosting the overall economic output.  (iv) Foreign Exchange Earnings: The export of manufactured goods provides foreign exchange earnings, improving the country's balance of payments and allowing for the import of essential goods and technology.  (v) Technological Advancement: The industrial sector often leads to technological innovation and transfer, enhancing productivity and fostering further economic development.  (vi) Infrastructure Development: Industrial growth stimulates the development of infrastructure such as roads, power supply, and telecommunications, which benefits the entire economy.  (vii) Improved Living Standards: By providing higher wages and a broader range of goods and services, the industrial sector can significantly improve the living standards of the population.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>2>a","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"State four migration patterns","images":[],"marking_scheme":"1. Rural-urban migration: Moving from rural areas to cities for better opportunities.  2. Urban-rural migration: Moving from cities to rural areas for a quieter life or to escape urban challenges.  3. Internal migration: Moving within a country's borders, often for economic or social reasons.  4. International migration: Moving across international borders, often for political, economic, or educational reasons.","marks":"4","difficulty":"1"},{"id":"theory>Geography>2024 Paper 2>2>b","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Explain five factors that can trigger population movement in Tropical Africa.","images":[],"marking_scheme":"1. Political instability: Conflict, war, or persecution can force people to flee their homes.  2. Economic opportunities: Better job prospects or higher wages can attract people to urban areas.  3. Environmental factors: Drought, famine, or natural disasters can lead to migration.  4. Social factors: Family reunification, marriage, or education can prompt movement.  5. Health concerns: Access to better healthcare or fleeing health crises can drive migration.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>2>c","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Highlight three effects of population movement on the destination region in Tropical Africa","images":[],"marking_scheme":"1. Cultural diversity: In-migration can bring new cultures, languages, and customs, enriching the destination region.  2. Economic growth: New arrivals can bring skills, entrepreneurial spirit, and increased economic activity.  3. Strain on resources: Rapid population growth can put pressure on infrastructure, services, and resources, leading to challenges in housing, healthcare, and education.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>3>a","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"What is birth rate?","images":[],"marking_scheme":"The birth rate is the number of live births per 1,000 people in a given population over a specific period, typically one year. It is an essential demographic indicator used to assess population growth and reproductive health trends.  OR  The birth rate is a demographic indicator that measures the frequency of live births in a specified population, expressed as the number of live births per 1,000 people in that population over the course of one year.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2024 Paper 2>3>b","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Outline three factors that affect birth rate in Tropical Africa","images":[],"marking_scheme":"(i) Cultural Practices: In many parts of Tropical Africa, cultural norms and traditions favour large families. High value is placed on having many children, which can increase the birth rate.  (ii) Economic Factors: In agrarian societies, children are often seen as economic assets who can contribute to the family's labour force. This economic benefit can drive higher birth rates.  (iii) Access to Education: Lower levels of education, particularly among women, often correlate with higher birth rates. Educated women tend to have fewer children as they have greater access to family planning information and career opportunities.  (iv) Health Care Accessibility: Limited access to healthcare, including reproductive health services and contraception, can result in higher birth rates.  (v) Government Policies: Policies that promote or discourage family planning can significantly impact birth rates. In some areas, lack of support for family planning services can lead to higher birth rates.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>3>c","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Highlight three advantages of over-population in Tropical Africa","images":[],"marking_scheme":"(i) Labour Force: A large population provides a substantial labour force, which can drive economic development if properly harnessed.  (ii) Market Size: Over-population can lead to a large domestic market, encouraging businesses to invest and thrive due to high demand for goods and services.  (iii) Innovation and Cultural Diversity: A diverse and large population can foster innovation and cultural richness, contributing to a dynamic and creative society.  (iv) Military Strength: A larger population can translate into a stronger military force, which may enhance national security.  (v) Human Resources: Over-population can provide a wealth of human resources, which can be advantageous for various sectors such as education, healthcare, and technology.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>3>d","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"d","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Identify three problems created by over-population in Tropical Africa","images":[],"marking_scheme":"(i) Resource Depletion: Over-population puts immense pressure on natural resources, leading to depletion and environmental degradation.  (ii) Unemployment: High population growth can result in insufficient job opportunities, leading to high levels of unemployment and underemployment.  (iii) Poor Living Conditions: Over-population can strain infrastructure and social services, resulting in overcrowded living conditions, inadequate housing, and poor sanitation.  (iv) Healthcare Strain: Over-population can overwhelm healthcare systems, making it difficult to provide adequate medical services to everyone.  (v) Food Security: High population growth can lead to food shortages and increased malnutrition as the demand for food outpaces supply.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>4>a","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw an outline map of Nigeria.  On the map, locate and name:                                         -one international airport;  -one river port;   -Lafia","images":["data:image/png;base64,"],"marking_scheme":"","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>4>b","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Outline four problems that affect transportation in Nigeria.","images":[],"marking_scheme":"1.\tPoor condition of roads  2.\t Poor maintenance of roads  3.\t High cost of maintenance of roads  4.\tPoor maintenance of vehicles  5.\tHigh cost of spare parts  6.\t High cost of fuel  7.\t High cost of transportation  8.\tFew seasonal roads.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>4>c","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"c","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"In what three ways has transportation contributed to the economic development of Nigeria?","images":[],"marking_scheme":"1. Movement of goods  2. Movement of people  3. Movement of services and information  4. Aids domestic trade  5. Provides employment   6. Diffusion of ideas and innovation  7. Opens up the interior for further development  8. Provides international link  9. Important for export and import of goods.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>5>a","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Outline five factors which determine what can be produced in Nigeria.","images":[],"marking_scheme":"1. Climate : Nigeria's tropical climate allows for the production of crops like cocoa, rubber, and palm oil.  2. Soil: The fertile soil in parts of Nigeria supports agriculture, while the sandy soil in other areas is suitable for livestock grazing.  3. Natural Resources: Nigeria's abundance of oil, natural gas, and minerals like iron ore and coal influences the production of petroleum products, steel, and other industries.  4. Labour: Nigeria's large population provides a significant workforce, influencing the production of labour-intensive industries like textiles and food processing.  5. Technology: The level of technological advancement in Nigeria, including infrastructure and equipment, affects the efficiency and productivity of various industries.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>5>b","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Identify five factors that hinder trade in Nigeria","images":[],"marking_scheme":"1. Inadequate Infrastructure: Poor road networks, congested ports, and limited rail transportation hinder the efficient movement of goods.  2. Corruption: Bureaucratic red tape, bribery, and other corrupt practices increase the cost and complexity of trade.  3. Security Concerns: Insecurity, terrorism, and piracy in some regions disrupt trade and discourage investment.  4. Regulatory Barriers: Complex and often changing regulations, as well as restrictive trade policies, can limit trade.  5. Lack of Access to Finance: Limited access to credit, high interest rates, and inadequate financial infrastructure can constrain trade growth.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>6>a","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw an outline map of Nigeria.  On the map, show and name:  -longitude 15oE;                                                     -Udi Hill;                                                            -Lokoja.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>6>b","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Outline three importance of highlands in Nigeria","images":[],"marking_scheme":"1. Agriculture: Highlands in Nigeria provide suitable terrain for agriculture, supporting crops like tea, coffee, and pyrethrum, which are significant contributors to the country's economy.  2. Tourism: The highlands offer scenic beauty, attracting tourists to destinations like the Jos Plateau, Obudu Plateau, and Mambilla Plateau, generating revenue and promoting local economies.  3. Water Resources: Highlands serve as water catchment areas, feeding rivers and streams that supply water for irrigation, drinking water, and hydroelectric power generation.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 2>6>c","subject":"Geography","year":"2024 Paper 2","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Identify four developmental problems arising from the presence of highlands in Nigeria.","images":[],"marking_scheme":"1. Accessibility Challenges: Steep terrain and poor road networks make it difficult to access highland areas, hindering economic development and social services delivery.  2. Soil Erosion: Heavy rainfall and steep slopes lead to soil erosion, landslides, and sedimentation, affecting agricultural productivity and water quality.  3. Limited Infrastructure: Inadequate infrastructure, including roads, bridges, and social amenities, constrains economic growth and social development in highland areas.  4. Environmental Degradation: Overexploitation of natural resources, deforestation, and pollution threaten the ecological balance and biodiversity of highland ecosystems.","marks":"8","difficulty":"3"}];